import { prisma } from '@/lib/db'
import Container from '@/components/ui/Container'
import Link from 'next/link'
import { notFound } from 'next/navigation'
import { Reveal } from '@/components/ui/Reveal'
// In a full production app you'd parse Phase 2's rich text content with a markdown parser like react-markdown.
// We'll safely render HTML if you store HTML, or we can just render the raw string for this Phase.

export async function generateMetadata({ params }) {
    const { slug } = await params
    const post = await prisma.post.findUnique({ where: { slug } })
    if (!post) return { title: 'Post Not Found' }

    return {
        title: `${post.title} | VPS Blog`,
        description: post.excerpt || 'Read the full article on VPS Digital.',
    }
}

export default async function BlogPostPage({ params }) {
    const { slug } = await params
    const post = await prisma.post.findUnique({
        where: { slug },
        include: {
            author: { select: { name: true, role: true } },
            category: true,
            tags: true,
        },
    })

    if (!post || !post.isPublished) {
        notFound()
    }

    // Estimate read time (assuming ~250 words per minute)
    const wordCount = post.content.split(/\s+/).length
    const readTime = Math.max(1, Math.ceil(wordCount / 250))

    return (
        <div className="min-h-screen bg-[#fafafa]">
            {/* Article Header */}
            <section className="bg-white pt-40 pb-20 border-b border-gray-100 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-[800px] h-[800px] bg-violet-50/50 rounded-full blur-[100px] -translate-y-1/2 pointer-events-none" />

                <Container className="max-w-4xl relative z-10">
                    <Reveal yOffset={30}>
                        <Link href="/blog" className="text-violet-600 font-bold text-sm mb-8 inline-flex items-center hover:text-violet-800 transition-colors">
                            ← Back to Engineering Blog
                        </Link>

                        <div className="flex flex-wrap items-center gap-4 mb-6">
                            {post.category && (
                                <span className="bg-cyan-100 text-cyan-700 font-bold text-xs uppercase tracking-wide px-3 py-1.5 rounded-full">
                                    {post.category.name}
                                </span>
                            )}
                            <span className="text-gray-400 font-semibold text-sm flex items-center gap-1.5">
                                📅 {new Date(post.createdAt).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}
                            </span>
                            <span className="text-gray-400 font-semibold text-sm flex items-center gap-1.5">
                                ⏱️ {readTime} min read
                            </span>
                        </div>

                        <h1 className="text-4xl md:text-5xl lg:text-6xl font-extrabold text-gray-900 leading-tight tracking-tight mb-8">
                            {post.title}
                        </h1>

                        <div className="flex items-center gap-4">
                            <div className="w-12 h-12 rounded-full bg-linear-to-br from-violet-600 to-cyan-500 text-white flex items-center justify-center font-bold text-lg shadow-md shadow-violet-200">
                                {post.author.name.charAt(0)}
                            </div>
                            <div>
                                <p className="font-bold text-gray-900">{post.author.name}</p>
                                <p className="text-sm font-medium text-gray-500">{post.author.role === 'SUPER_ADMIN' ? 'Head of Engineering' : 'Technical Author'}</p>
                            </div>
                        </div>
                    </Reveal>
                </Container>
            </section>

            {/* Featured Image if exists */}
            {post.featuredImg && (
                <div className="max-w-5xl mx-auto px-4 -mt-10 relative z-20">
                    <Reveal yOffset={40} delay={0.2}>
                        <div className="rounded-[2rem] overflow-hidden shadow-2xl shadow-gray-200/50 border-4 border-white h-[400px] md:h-[500px] bg-gray-100">
                            <img src={post.featuredImg} alt={post.title} className="w-full h-full object-cover" />
                        </div>
                    </Reveal>
                </div>
            )}

            {/* Article Body */}
            <section className="py-20">
                <Container className="max-w-3xl">
                    <Reveal delay={post.featuredImg ? 0.3 : 0.2}>
                        {/* We use prose-lg for gorgeous typography inside the article */}
                        <article className="prose prose-lg prose-violet prose-headings:font-extrabold prose-headings:tracking-tight prose-p:text-gray-600 prose-p:leading-relaxed max-w-none">
                            {/* In Phase 2 we map newline characters to breaks for simple text. In a final prod this would use react-markdown */}
                            {post.content.split('\n').map((paragraph, idx) => (
                                paragraph.trim() !== '' ? <p key={idx}>{paragraph}</p> : <br key={idx} />
                            ))}
                        </article>

                        {/* Tags */}
                        {post.tags && post.tags.length > 0 && (
                            <div className="mt-16 pt-8 border-t border-gray-100 flex flex-wrap gap-2">
                                <span className="text-gray-900 font-bold mr-2 my-auto">Tags:</span>
                                {post.tags.map(tag => (
                                    <span key={tag.id} className="bg-gray-100 text-gray-600 px-3 py-1 rounded-full text-sm font-bold hover:bg-gray-200 cursor-pointer transition-colors">
                                        #{tag.name}
                                    </span>
                                ))}
                            </div>
                        )}
                    </Reveal>
                </Container>
            </section>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import Link from 'next/link'
import { showSuccess, showError } from '@/lib/swal'

export default function AdminMediaLibrary() {
    const [media, setMedia] = useState([])
    const [loading, setLoading] = useState(true)
    const [uploading, setUploading] = useState(false)
    const [error, setError] = useState('')

    const fetchMedia = () => {
        setLoading(true)
        fetch('/api/admin/media')
            .then(res => res.json())
            .then(data => {
                if (Array.isArray(data)) setMedia(data)
                setLoading(false)
            })
            .catch(() => {
                showError('Failed to load media.')
                setLoading(false)
            })
    }

    useEffect(() => {
        fetchMedia()
    }, [])

    const handleFileUpload = async (e) => {
        const file = e.target.files[0]
        if (!file) return

        if (!file.type.startsWith('image/')) {
            showError('Only image files are allowed.')
            return
        }

        if (file.size > 5 * 1024 * 1024) { // 5MB limit
            showError('File size must be under 5MB.')
            return
        }


        setUploading(true)

        const formData = new FormData()
        formData.append('file', file)

        try {
            const res = await fetch('/api/admin/media', {
                method: 'POST',
                body: formData,
            })

            if (!res.ok) throw new Error('Upload failed')

            // Refresh gallery
            fetchMedia()
            showSuccess('Image uploaded successfully!')
        } catch (err) {
            showError(err.message)
        } finally {
            setUploading(false)
            e.target.value = '' // Reset input
        }
    }

    const copyToClipboard = (url) => {
        navigator.clipboard.writeText(window.location.origin + url)
        showSuccess('Image URL copied to clipboard!')
    }

    return (
        <div className="w-full">
            <div className="max-w-6xl mx-auto px-6 py-10 animate-fade-up">
                <div className="mb-10 flex flex-col md:flex-row md:items-center justify-between bg-white border border-gray-100 rounded-2xl p-6 shadow-sm gap-4">
                    <div>
                        <h1 className="text-2xl font-extrabold text-gray-900 tracking-tight">Global Media Library</h1>
                        <p className="text-gray-500 font-medium text-sm mt-2">
                            Upload images to embed in your dynamic CMS pages and Blog Engine.
                        </p>
                    </div>

                    <div>

                        <label className={`cursor-pointer inline-flex items-center justify-center btn-primary py-3 px-6 shadow-sm ${uploading ? 'opacity-50 pointer-events-none' : ''}`}>
                            <input
                                type="file"
                                className="sr-only"
                                accept="image/*"
                                onChange={handleFileUpload}
                                disabled={uploading}
                            />
                            {uploading ? 'Uploading...' : 'Upload Image'}
                        </label>
                    </div>
                </div>

                {loading ? (
                    <div className="py-20 text-center text-gray-400 font-bold">Loading library...</div>
                ) : (
                    <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
                        {media.length > 0 ? media.map(item => (
                            <div key={item.id} className="group bg-white border border-gray-100 rounded-2xl overflow-hidden shadow-sm hover:border-violet-300 transition-colors flex flex-col">
                                <div className="h-40 bg-gray-50 flex items-center justify-center overflow-hidden border-b border-gray-50 relative">
                                    <img src={item.url} alt={item.filename} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
                                    <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-3">
                                        <button
                                            onClick={() => copyToClipboard(item.url)}
                                            className="px-4 py-2 bg-white text-gray-900 rounded-xl text-xs font-bold hover:scale-105 transition-transform"
                                        >
                                            Copy Link
                                        </button>
                                    </div>
                                </div>
                                <div className="p-4 flex flex-col flex-1">
                                    <p className="text-xs font-bold text-gray-900 truncate mb-1">{item.filename}</p>
                                    <p className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mt-auto flex items-center justify-between">
                                        <span>{(item.sizeBytes / 1024).toFixed(1)} KB</span>
                                        <span>{new Date(item.createdAt).toLocaleDateString()}</span>
                                    </p>
                                </div>
                            </div>
                        )) : (
                            <div className="col-span-full py-20 bg-white border border-dashed border-gray-200 rounded-3xl text-center flex flex-col items-center justify-center">
                                <div className="w-16 h-16 rounded-full bg-gray-50 flex items-center justify-center text-2xl mb-4">🖼️</div>
                                <p className="text-gray-900 font-bold">No media uploaded yet.</p>
                                <p className="text-gray-500 text-sm mt-1">Upload your first image to use in blog posts.</p>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    )
}
